 ctx.fillStyle = getComputedStyle(document.body).getPropertyValue('--text-muted').trim();
 ctx.font = '11px Segoe UI';
 ctx.textAlign = 'center';
 ctx.fillText('Contribution to Overall Heterogeneity', w / 2, h - 10);
