function downloadTablesCSV() {
 const effectType = APP.config.outcomeType === 'survival' ? 'HR' :
 APP.config.outcomeType === 'binary' ? 'OR' : 'MD';
 const isLogScale = APP.config.outcomeType !== 'continuous';

 let csv = 'STUDY CHARACTERISTICS\n';
 csv += 'Study,Treatment N,Control N,Treatment Events,Control Events\n';

 const studies = [...new Set(APP.data.map(d => d.study_id || d.study))];
 studies.forEach(study => {
 const studyData = APP.data.filter(d => (d.study_id || d.study) === study);
 const treated = studyData.filter(d => d.treatment === 1);
 const control = studyData.filter(d => d.treatment === 0);
 const eventVar = APP.config.eventVar || 'event';

 csv += `${study},${treated.length},${control.length},${treated.filter(d => d[eventVar] === 1).length},${control.filter(d => d[eventVar] === 1).length}\n`;
 });

 csv += '\nEFFECT ESTIMATES\n';
 csv += `Study,N,Events,${effectType},Lower CI,Upper CI,Weight\n`;

 APP.results.studies.forEach(s => {
 csv += `${s.study},${s.n},${s.events},${(isLogScale ? Math.exp(s.effect) : s.effect).toFixed(4)},${(isLogScale ? Math.exp(s.lower) : s.lower).toFixed(4)},${(isLogScale ? Math.exp(s.upper) : s.upper).toFixed(4)},${(s.weight * 100).toFixed(1)}%\n`;
 });

 csv += `\nPooled,${APP.results.studies.reduce((s, r) => s + r.n, 0)},${APP.results.studies.reduce((s, r) => s + (r.events || 0), 0)},${(isLogScale ? Math.exp(APP.results.pooled.effect) : APP.results.pooled.effect).toFixed(4)},${(isLogScale ? Math.exp(APP.results.pooled.lower) : APP.results.pooled.lower).toFixed(4)},${(isLogScale ? Math.exp(APP.results.pooled.upper) : APP.results.pooled.upper).toFixed(4)},100%\n`;

 const blob = new Blob([csv], { type: 'text/csv' });
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url;
 a.download = 'ipd_meta_analysis_tables.csv';
 a.click();
 }

