 ctx.fill();

 ctx.fillStyle = '#ccc';
 ctx.font = '12px monospace';
 ctx.textAlign = 'center';
 ctx.fillText('Outcome 1 Effect', width / 2, height - 15);
 ctx.save();
 ctx.translate(20, height / 2);
 ctx.rotate(-Math.PI / 2);
